// Получаем входящие данные
const item = $input.first();

// Извлекаем чистый текст из ответа Gemini
const topic = item.json.content.parts[0].text.trim();

// Записываем чистую тему в новый ключ
item.json.cleanTopic = topic;

// Возвращаем обновленный объект
return item;

// Получаем входящие данные от Gemini
const item = $input.first();

// 1. Извлекаем "грязный" текст из сложной структуры ответа
// Мы используем '?' для безопасного доступа, чтобы избежать ошибок, если структура изменится
const rawText = item?.json?.content?.parts[0]?.text

if (!rawText) {
  throw new Error("Не удалось найти текстовую часть в ответе от Gemini.");
}

// 2. Очищаем строку от Markdown-блоков и лишних пробелов
// Эта команда удаляет ```json в начале и ``` в конце
const cleanedJsonString = rawText.replace(/^```json\s*|\s*```$/g, '').trim();

try {
  // 3. Парсим (превращаем) очищенную строку в настоящий JSON-объект
  const parsedData = JSON.parse(cleanedJsonString);
  const topicList = parsedData.topics;

  // 4. Проверяем, что у нас есть список тем
  if (!topicList || topicList.length === 0) {
    throw new Error("Не удалось сгенерировать или найти список тем в JSON.");
  }

  // 5. Выбираем случайную тему (эта логика остается прежней)
  const randomIndex = Math.floor(Math.random() * topicList.length);
  const randomTopic = topicList[randomIndex];

  // Записываем финальный результат в основной объект
  item.json.selectedQuery = randomTopic;

  // Возвращаем объект для следующего узла
  return item;

} catch (error) {
  // Если Gemini вернет некорректный JSON, мы увидим понятную ошибку
  throw new Error(`Ошибка парсинга JSON: ${error.message}`);
}

for (const item of $('Get Table Data').all()) {
  const url = item.json.URL ? String(item.json.URL).trim() : "";
  if (url) {
    let hostname = url.replace(/^[a-zA-Z]+:\/\//, "").split("/")[0];
    if (hostname.startsWith("www.")) {
      hostname = hostname.slice(4);
    }
    item.json.Host = hostname;
  }
}
return $('Get Table Data').all();

// Получаем текущий элемент (это массив, например, ["202504...", "https://...", ...])
const snapshot = $input.item.json;

// 1. Отсеиваем заголовок
if (snapshot[0] === 'timestamp') {
  return null;
}

// 2. Извлекаем данные из массива
const [timestamp, original, mimetype, statuscode, length] = snapshot;
// Снижаем порог, чтобы включать небольшие, но валидные страницы
const minLength = 500; // <<< ИЗМЕНЕНИЕ ЗДЕСЬ

// 3. Проверяем размер и возвращаем результат
if (parseInt(length) > minLength) {
  const waybackUrl = `http://web.archive.org/web/${timestamp}/${original}`;

  // Возвращаем объект в нужном нам формате.
  return { json: { downloadUrl: waybackUrl } };
}

// Если размер слишком маленький, отбрасываем этот снимок
return null;

// Получаем все входящие элементы (5 страниц для одного сайта)
const items = $input.all();

if (items.length === 0) {
  return [];
}

// Берем метаданные (Host, row_number) из ПЕРВОГО элемента этой группы.
// Важно: предполагается, что все 5 снимков принадлежат одному сайту.
// Поскольку мы используем n8n (cloud), контекст выполнения обычно сохраняется корректно.
// Но нам нужно убедиться, что мы берем row_number именно от текущего обрабатываемого элемента.

// Мы можем взять originalJson из первого элемента items, так как 'Фильтр снимков'
// должен был пробросить контекст, но он этого не сделал явно.
// Однако, мы можем обратиться к родительскому узлу 'extract host'
// и найти там элемент, соответствующий нашему хосту.

// Более простой и надежный вариант для текущей структуры:
// Получаем все HTML данные в массив
let newArray = [];
let currentDownloadUrl = "";

for (const item of items) {
  newArray.push(item.json.data);
  if(item.json.downloadUrl) currentDownloadUrl = item.json.downloadUrl;
}

// Нам нужно найти исходные данные (row_number) для этого набора снимков.
// Мы ищем в узле 'extract host' элемент, чей домен совпадает с тем, что мы скачивали.
// Это немного "хак", но он работает, если URL архива содержит домен.

const allHosts = $('extract host').all();
let originalJson = {};

// Пытаемся найти правильный row_number
for(const hostItem of allHosts) {
    if(currentDownloadUrl.includes(hostItem.json.Host)) {
        originalJson = hostItem.json;
        break;
    }
}

// Если не нашли (редкий случай), берем первый попавшийся как фоллбэк
if(!originalJson.Host) {
    originalJson = $('extract host').first().json;
}

const combinedData = { ...originalJson, sites: newArray };

return [{ json: combinedData }];

const items = $input.all();

// Проходим по всем элементам
const result = items.map((item) => {
  let text = item?.json?.content?.parts[0]?.text;

  // Очистка JSON от markdown
  if (typeof text === 'string') {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/, '').trim();
  }

  let validJson = {};
  try {
    validJson = JSON.parse(text);
  } catch (e) {
    // Если не распарсилось, оставляем пустым или логируем
    validJson = { error: "Failed to parse JSON" };
  }

  // Очистка текста от переносов строк
  if (validJson.clean_text && typeof validJson.clean_text === 'string') {
    validJson.clean_text = validJson.clean_text.replace(/\n/g, " ");
  }

  // --- ГЛАВНОЕ ИСПРАВЛЕНИЕ ---
  // Мы возвращаем объект, который содержит И старые данные (item.json), И новые (validJson)
  return {
    json: {
      ...item.json,   // Сохраняем row_number, Host и всё остальное
      ...validJson    // Добавляем topic, summary, clean_text
    }
  };
});

return result;

const item = $input.item;
const html = item.json.data;

// Сначала ищем iframe
const iframeMatch = html.match(/<iframe id="playback" src="([^"]+)"/);
if (iframeMatch && iframeMatch[1]) {
  item.json.nextUrl = iframeMatch[1];
  // Мы нашли URL для следующего шага
