}

// Если iframe не найден, ищем главный frameset
const frameMatch = html.match(/<frame name="main" src="([^"]+)"/);
if (frameMatch && frameMatch[1]) {
  item.json.nextUrl = frameMatch[1];
  // Мы нашли URL для следующего шага
