}

// Если не найдено ни iframe, ни frame, значит, это уже контент
// Просто перекладываем его в финальное поле
item.json.finalHtml = html;
return item;

const items = $input.all();

// Определяем начало текущей недели (понедельник)
const now = new Date();
const dayOfWeek = now.getDay(); // 0=Воскресенье, 1=Понедельник, ..., 6=Суббота
const diff = now.getDate() - dayOfWeek + (dayOfWeek === 0 ? -6 : 1); // формула для получения понедельника
const startOfWeek = new Date(now.setDate(diff));
startOfWeek.setHours(0, 0, 0, 0); // Устанавливаем время на начало дня

let weeklyCount = 0;

for (const item of items) {
  if (item.json.Timestamp) {
    const executionDate = new Date(item.json.Timestamp);
    // Проверяем, что дата выполнения больше или равна началу этой недели
    if (executionDate >= startOfWeek) {
      weeklyCount++;
    }
  }
}

return [{
  json: {
    weeklyCount: weeklyCount
  }
}];

// n8n Code node — robust Gemini → [{ id, slug, prompt, width, height }]
// FINAL VERSION: Formats output specifically for the Gemini node's batch image generation.

function readGeminiText(j) {
  // Try the common shapes in order
  return (
    j?.content?.parts?.[0]?.text ??
    j?.candidates?.[0]?.content?.parts?.[0]?.text ??
    j?.text ??
    j?.message?.content ??
    null
  );
}

function tryParseArray(raw) {
  if (raw == null) return null;
  const str = String(raw).trim();
  // 1) direct JSON
  try { 
    const parsed = JSON.parse(str);
    return Array.isArray(parsed) ? parsed : null;
  } catch (_) {}
  // 2) find first JSON array in text
  const m = str.match(/\[[\s\S]*\]/);
  if (!m) return null;
  try {
    const parsed = JSON.parse(m[0]);
    return Array.isArray(parsed) ? parsed : null;
  } catch (_) {
    return null;
  }
}

function sanitizeSlug(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^\p{Letter}\p{Number}\-]+/gu, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');
}

function arToSize(ar) {
  const map = {
    '16:9': [1280, 720], '9:16': [720, 1280], '4:3':  [1200, 900],
    '3:2':  [1200, 800], '1:1':  [1024, 1024],
  };
  return map[ar] || [1024, 1024];
}

function deriveSizeFromPrompt(prompt, fallbackW, fallbackH) {
  const m = String(prompt).match(/--ar\s+(\d+:\d+)/i);
  if (m) return arToSize(m[1]);
  return [fallbackW ?? 1024, fallbackH ?? 1024];
}

// This function now creates the EXACT structure the Gemini node expects.
function normalizeOne(x, idx) {
  const id = x.img_id ?? x.id ?? String(idx + 1);
  const slug = sanitizeSlug(x.slug ?? x.title ?? x.name ?? `item-${id}`);
  let promptText = String(x.prompt ?? x.text ?? x.description ?? '').trim();

  let width = Number(x.width) || null;
  let height = Number(x.height) || null;
  const arMatch = promptText.match(/--ar\s+(\S+)/i);
  if (arMatch) promptText = promptText.replace(/--ar\s+\S+/i, '').trim();
  [width, height] = deriveSizeFromPrompt(promptText, width, height);

  if (!promptText) throw new Error(`Элемент без prompt (slug="${slug}")`);

  // *** ГЛАВНОЕ ИЗМЕНЕНИЕ ***
  // Создаем объект json, содержащий метаданные (id, slug) И
  // обязательную структуру 'content.parts' для промпта.
  return { 
    json: { 
      id, 
      slug, 
      width, 
      height, 
      content: { 
        parts: [{ text: promptText }] 
      } 
    } 
  };
}

// ---- MAIN ----
const items = $input.all();
const out = [];

for (const it of items) {
  const j = it.json || {};

  // Case A: Pass-through for items that already have a prompt.
  // We'll normalize them to the required structure.
  if (j.prompt && (j.slug || j.id)) {
    out.push(normalizeOne(j, out.length));
    continue;
  }

  // Case B: Extract from a raw Gemini text response.
  const raw = readGeminiText(j);

  // B1: If raw is a single prompt string
  if (raw && !raw.trim().startsWith('[')) {
    out.push(normalizeOne({ ...j, prompt: raw }, out.length));
    continue;
  }

  // B2: If raw contains a JSON array
  const arr = tryParseArray(raw);
  if (arr) {
    const list = (arr[0] && Array.isArray(arr[0].images)) ? arr[0].images : arr;
    for (const itemData of list) {
      out.push(normalizeOne(itemData, out.length));
    }
    continue;
  }
}

if (out.length === 0) {
  throw new Error('Парсер не нашёл ни одного валидного элемента для генерации.');
}

return out;

// 1. Получаем все компоненты из предыдущих узлов
const htmlItem = $('HTML-Верстальщик').first();
const cssItem = $('Generate CSS').first();
const jsItem = $('Generate JS').first();
const currentYear = new Date().getFullYear();

// 2. Проверяем, что все данные пришли, чтобы избежать ошибок
if (!htmlItem || !cssItem || !jsItem) {
  throw new Error("Один из компонентов для сборки (HTML, CSS, JS) отсутствует.");
}
let allHtml = htmlItem.json.content.parts.map(part => part.text ).join('\n')

// Извлекаем чистый текст из ответов LLM gemini
let finalHtml = allHtml.replace(/^```html\s*|```\s*$/g, '').trim().replace(/\b(20[2-9]\d)\b/g, currentYear.toString());
const finalJs = jsItem.json.content.parts[0].text.replace(/^```javascript\s*|```\s*$/g, '').trim();
const finalCss = cssItem.json.content.parts[0].text.replace(/^```css\s*|```\s*$/g, '').trim();

// --- НАЧАЛО НОВОЙ ЛОГИКИ ---
// Ищем "casinoN utan svensk licens" без учета регистра и заменяем, сохраняя исходный регистр слова "casino"
finalHtml = finalHtml.replace(/\b(casino)N(\sutan\ssvensk\slicens)\b/gi, (match, p1, p2) => {
    // p1 будет "casino" (или "Casino", "CASINO" и т.д. в зависимости от найденного)
    // p2 будет " utan svensk licens"
    return p1 + p2; // Просто соединяем две части, удаляя "N"
});
// --- КОНЕЦ НОВОЙ ЛОГИКИ ---

// 3. Собираем финальный HTML-файл
let assembledHtml = finalHtml;

// Вставляем CSS прямо перед закрывающим тегом </head>
assembledHtml = assembledHtml.replace(/(<\/head>)/i, `<style>${finalCss}</style>$1`);

// Вставляем JS прямо перед закрывающим тегом </body>
assembledHtml = assembledHtml.replace(/(<\/body>)/i, `<script type="module" defer>${finalJs}</script>$1`);

// 4. Возвращаем результат в формате, который ожидает ваш следующий узел 'Merge1'
// Мы создаем binary-объект, готовый для архивации
return [{
  json: {
    // Передаем дальше исходные данные, если они нужны
    ...$input.first().json,
    fileName: 'index.html' // Явно указываем имя файла
  },
  binary: {
    index_html: { // <--- Уникальное имя!
      data: Buffer.from(assembledHtml, 'utf8').toString('base64'),
      fileName: 'index.html',
      mimeType: 'text/html'
    }
  }
}];

// Преобразуем вход (могут прийти: несколько айтемов или один айтем с массивом)
const inputItems = [$input.first()]
let payloads = inputItems.map(i => i.json);
if (inputItems.length === 1 && Array.isArray(inputItems[0].json)) {
  payloads = inputItems[0].json;
}

function extractText(payload) {
  if (typeof payload === 'string') return payload;
  if (payload?.content?.parts?.[0]?.text) return payload.content.parts[0].text;
  if (payload?.text) return payload.text;
  // на всякий случай
  return JSON.stringify(payload);
}

function stripCodeFence(s) {
  // срезаем начальный ```html/``` и конечные ```
  return String(s)
    .replace(/^\s*```(?:html)?\s*\n?/, '')
    .replace(/\n?\s*```\s*$/, '')
    .trim();
}

function slugify(s) {
  return String(s)
    .toLowerCase()
    .replace(/&/g, ' och ')                 // & → «och» (швед.)
    .replace(/[^a-z0-9\u00c0-\u024f\s-]+/gi, '') // латиница + диакритики
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '') || 'gemini-page';
}

const out = [];

for (let i = 0; i < payloads.length; i++) {
  const textRaw = extractText(payloads[i]);
  let html = stripCodeFence(textRaw);

  // если пришёл не полный HTML — обернём
  if (!/<!doctype html>/i.test(html) && !/<html[\s>]/i.test(html)) {
    html = `<!doctype html><html><head><meta charset="utf-8"><title>Gemini Page</title></head><body>${html}</body></html>`;
  }

  const titleMatch = html.match(/<title>([\s\S]*?)<\/title>/i);
  const title = (titleMatch && titleMatch[1].trim()) || 'Gemini Page';
  const fileName = `404.html`;

  out.push({
    json: { fileName, title },
    binary: {
      file_404: { // <--- Уникальное имя!
        data: Buffer.from(html, 'utf8').toString('base64'),
        fileName: fileName,
        mimeType: 'text/html'
      }
    }
  });
}

return out;

// Явно берем данные из узла "Code in JavaScript1", где они были подготовлены.
// Это делает код независимым от промежуточных узлов (например, SSH).
const sourceItem = $('Extract the domain from the table').first();

// Проверяем, что данные из исходного узла существуют
if (!sourceItem || !sourceItem.json || !sourceItem.json.domain) {
  // Если данных нет, возвращаем пустой результат, чтобы не останавливать workflow.
  // Можно также выбросить ошибку: throw new Error("Не найден домен в узле 'Code in JavaScript1'");
  return []; 
}

// Теперь мы можем безопасно использовать данные.
const jsonData = sourceItem.json;
const BASE_URL = 'https://' + jsonData.domain;

const robotsContent = `User-agent: *
Allow: /
Sitemap: ${BASE_URL.replace(/\/$/,'')}/sitemap.xml
`.trim() + '\n';

// Собираем и возвращаем итоговый item.
return [{
  json: { 
    // Передаем дальше все исходные данные на всякий случай.
    ...jsonData,
    fileName: 'robots.txt', 
    kind: 'robots' 
  },
  binary: {
    // Используем уникальный ключ 'robots_txt' во избежание конфликтов при слиянии.
    robots_txt: {
      data: Buffer.from(robotsContent, 'utf8').toString('base64'),
      fileName: 'robots.txt',
      mimeType: 'text/plain'
    }
  }
}];

// Явно берем данные из узла "Code in JavaScript1", где они были подготовлены.
const sourceItem = $('Extract the domain from the table').first();

// Проверяем, что данные из исходного узла существуют
if (!sourceItem || !sourceItem.json || !sourceItem.json.domain) {
  // Если данных нет, возвращаем пустой результат.
  return []; 
}

// Теперь мы можем безопасно использовать данные.
const jsonData = sourceItem.json;
const BASE_URL = 'https://' + jsonData.domain;
const now = new Date().toISOString().slice(0, 10); // Текущая дата в формате YYYY-MM-DD

const sitemapContent = `<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
  <url><loc>${BASE_URL.replace(/\/$/,'')}/</loc><lastmod>${now}</lastmod><priority>1.0</priority></url>
</urlset>
`;

// Собираем и возвращаем итоговый item.
return [{
  json: { 
    // Передаем дальше все исходные данные
    ...jsonData,
    fileName: 'sitemap.xml', 
    kind: 'sitemap' 
  },
  binary: {
    // Используем уникальный ключ 'sitemap_xml'
    sitemap_xml: {
      data: Buffer.from(sitemapContent, 'utf8').toString('base64'),
      fileName: 'sitemap.xml',
      mimeType: 'application/xml'
    }
  }
}];

// 1. Получаем исходные данные из самого надежного источника - узла "Code in JavaScript1".
const sourceItem = $('Extract the domain from the table').first();

// 2. Если по какой-то причине данных нет, прекращаем выполнение, чтобы избежать ошибок.
if (!sourceItem || !sourceItem.json) {
  return []; 
}
const jsonData = sourceItem.json;
const rawUrl = jsonData.URL || '';

// 3. Создаем базовую часть .htaccess, которая нужна всегда.
let htaccessContent = `
ErrorDocument 404 /404.html

RewriteEngine on
RewriteBase /

RewriteCond %{REQUEST_URI} !/$
RewriteCond %{REQUEST_URI} !\\.[a-zA-Z0-9]{2,5}$
RewriteCond %{REQUEST_URI} !^$
RewriteRule .* https://%{HTTP_HOST}%{REQUEST_URI}/ [R=301,L]

RewriteCond %{QUERY_STRING} .
RewriteRule .* https://%{HTTP_HOST}/$0? [R=301,L]
`.trim();

// 4. Проверяем условие: если в исходном URL есть "www", добавляем блок для редиректа.
if (rawUrl.includes('www.')) {
  const wwwRedirectBlock = `
# Force WWW (redirect non-www to www)
RewriteCond %{HTTP_HOST} !^www\\.
RewriteRule ^(.*)$ https://www.%{HTTP_HOST}/$1 [R=301,L]
`.trim();

  // Вставляем блок после RewriteBase /
  htaccessContent = htaccessContent.replace(
    'RewriteBase /', 
    'RewriteBase /\n\n' + wwwRedirectBlock
  );
}

// 5. Готовим и возвращаем итоговый item, сохраняя все исходные данные.
const binaryData = {
  data: Buffer.from(htaccessContent, 'utf8').toString('base64'),
  fileName: '.htaccess',
  mimeType: 'text/plain'
};

return [{
  json: {
    ...jsonData, // Сохраняем все данные, которые были до этого
    fileName: '.htaccess',
    kind: 'htaccess'
  },
binary: {
  htaccess: { // <--- Уникальное имя!
    data: Buffer.from(htaccessContent, 'utf8').toString('base64'),
    fileName: '.htaccess',
    mimeType: 'text/plain'
  }
}
}];

// Получаем все пакеты данных (items), которые пришли от узла "Edit Image"
const imageItems = $input.all();
// Получаем ВСЕ пакеты данных из исходного узла "Парсер Gemini" для получения слагов
const slugItems = $items('Парсер Gemini1');

if (imageItems.length !== slugItems.length) {
  throw new Error(`Несоответствие количества элементов: получено ${imageItems.length} изображений, но ожидалось ${slugItems.length} слагов.`);
}

for (let i = 0; i < imageItems.length; i++) {
  const currentImageItem = imageItems[i];

  // Берем slug из соответствующего по порядку пакета данных из "Парсер Gemini"
  const slug = slugItems[i].json.slug;

  if (!slug) {
