  // Это работает, если количество входящих и исходящих элементов совпадает
  if (!aiData && generatedItems.length === tableRows.length) {
      const item = generatedItems[i];
      if (item) {
          aiData = {
              query: item.json.selectedQuery,
              topic: item.json.cleanTopic || item.json.topic
          };
      }
  }

