// 1. Получаем результаты от SSH (предыдущий узел)
const sshItems = $input.all();

// 2. Получаем исходные данные с Тематикой и Query (из узла перед SSH)
// Важно: убедитесь, что имя узла в кавычках точное
const sourceItems = $items('Extract the domain from the table');

const result = [];

for (let i = 0; i < sshItems.length; i++) {
  // Берем результат SSH для текущей строки
  const sshItem = sshItems[i];

  // Берем исходные данные для ТОЙ ЖЕ строки (по индексу)
  // Если вдруг индексы не совпадут (редко), берем пустой объект
  const sourceData = sourceItems[i] ? sourceItems[i].json : {};

  // Парсим ответ сервера
  let serverInfo = {};
  const stdout = sshItem.json.stdout;

  if (stdout) {
    try {
      serverInfo = JSON.parse(stdout);
      if (serverInfo.error) {
        // Если сервер вернул JSON с ошибкой, сохраняем её
        serverInfo = { ...serverInfo, ssh_error: serverInfo.error };
      }
    } catch (e) {
      serverInfo = { ssh_error: `Failed to parse server response: ${e.message}` };
    }
  } else {
    serverInfo = { ssh_error: "SSH command returned no output." };
  }

  // 3. ОБЪЕДИНЕНИЕ
  // Мы создаем новый объект, который содержит:
  // - Все исходные поля (URL, Тематика, Query, row_number...)
  // - Поля, полученные от сервера (username, sitepath...)
  result.push({
    json: {
      ...sourceData,  // <-- Вот это возвращает ваши потерянные поля
      ...serverInfo
    }
  });
}

return result;

