// 1) Берём сырой SVG
let svgRaw = $input.first().json.message?.content ||  $input.first().json.content?.parts?.[0]?.text;

// 2) Чистим: убираем ```svg/``` и BOM, схлопываем пробелы
let svgClean = svgRaw
  .replace(/```[\w-]*\n?|\r|\n|```/g, "")     // убираем ```svg ... ```
  .replace(/^\uFEFF/, "")                     // BOM
  .trim()
  .replace(/\s{2,}/g, " ");                   // косметика

// 3) Гарантируем xmlns и фиксируем currentColor (часто «пропадает» в favicon)
if (!/xmlns=/.test(svgClean)) {
  svgClean = svgClean.replace("<svg", '<svg xmlns="http://www.w3.org/2000/svg"');
}
svgClean = svgClean.replace(/\bcurrentColor\b/g, "#000"); // при желании — свой брендовый цвет

// 4) Base64 (строго UTF-8) и валидация
const b64 = Buffer.from(svgClean, "utf8").toString("base64");
if (/[^A-Za-z0-9+/=]/.test(b64)) {
  throw new Error("Base64 содержит недопустимые символы — проверь кодировку пайплайна.");
}
const linkBase64 =
  `<link rel="icon" type="image/svg+xml" sizes="any" href="data:image/svg+xml;base64,${b64}">`;

// 5) URL-энкод без base64 — часто устойчивее к «перекодировкам»
const encoded = encodeURIComponent(svgClean)
  .replace(/%20/g, " ")
  .replace(/%0A/g, "")
  .replace(/%22/g, "'")
  .replace(/%3D/g, "=")
  .replace(/%3A/g, ":")
  .replace(/%2F/g, "/")
  .replace(/%3B/g, ";")
  .replace(/%2C/g, ",")
  .replace(/%23/g, "%23"); // # обязан быть экранирован
const linkUri =
  `<link rel="icon" type="image/svg+xml" sizes="any" href="data:image/svg+xml,${encoded}">`;

// 6) Отдаём обе версии — выбери под окружение (или оставь обе)
return [{
  json: {
    favicon_link_tag_base64: linkBase64,
    favicon_link_tag_uri: linkUri
  }
}];

