  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();
const designSystem = JSON.parse(cleaned);

// 2. Извлекаем 'design_seed'
const seed = designSystem.design_seed;
if (!seed) {
  throw new Error("В JSON от Архитектора отсутствует 'design_seed'.");
}

// 3. Функция для хеширования и кодирования (надежная)
function generatePfx(inputString) {
  // Создаем хеш SHA-256 и берем первые 4 байта (32 бита)
  const hash = crypto.createHash('sha256').update(inputString).digest();
  const int32 = hash.readUInt32BE(0);

  // Конвертируем в base36 и берем 4 символа
  const pfxValue = int32.toString(36).slice(0, 4);
  return 'x' + pfxValue.toLowerCase().padStart(4, '0');
}

// 4. Генерируем pfx
const pfx = generatePfx(seed);

// 5. ДОБАВЛЯЕМ 'pfx' в наш JSON-объект
designSystem.pfx = pfx;

