// Оборачиваем его обратно в структуру, которую ожидают другие LLM-узлы
return [{
  json: {
    content: {
      parts: [{
        text: JSON.stringify(designSystem, null, 2) // Возвращаем красивый JSON
      }]
    }
  }
}];
